# Update function
def update_json(file_path, updates):
    with open(file_path, 'r') as f:
        data = json.load(f)
    
    modified_count = 0
    for chapter in data['chapters']:
        for module in chapter['modules']:
            if module['id'] in updates:
                upd = updates[module['id']]
                module['title'] = upd['title']
                module['duration'] = upd['duration']
                module['keyPoints'] = upd['keyPoints']
                module['fullText'] = upd['fullText']
                # Optional: maintain alignment footer if provided in text, else keep existing?
                # The user says "MANTEN LAS REFERENCIAS SI HAY AL LAS PAGINAS Y SECCIONES DEL LIBRO BLUEBOOK, NGSS Y EC009 SEP CONOCER"
                # Looking at the provided text, some have footers like "🔖 Bluebook v1..."
                # I will trust the fullText provided.
                modified_count += 1
    
    with open(file_path, 'w') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    
    return modified_count

# Perform update
count = update_json('/Users/yepz/JSweb/data/modules.json', updates)
print(f"Updated {count} modules in data/modules.json")

# Generate new word counts for report
report = []
for mid, upd in updates.items():
    words = len(upd['fullText'].split())
    reading_time = (words // 100) + 1
    status = "✅ HIFI" if words >= 900 else "⚠️ CORTO"
    report.append(f"| {mid} | {upd['title']} | {words} | {reading_time} min | {status} |")

for line in report:
    print(line)
